import{_ as r,C as n,o as i,c as s,j as o,a,E as l,a3 as d}from"./chunks/framework.ZM1D-rQ5.js";const w=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md","lastUpdated":1782054810000}'),c={name:"changelog.md"},h={id:"v1-4-6",tabindex:"-1"};function u(g,e,p,m,f,b){const t=n("Badge");return i(),s("div",null,[e[3]||(e[3]=o("h1",{id:"changelog",tabindex:"-1"},[a("Changelog "),o("a",{class:"header-anchor",href:"#changelog","aria-label":'Permalink to "Changelog"'},"‚Äã")],-1)),e[4]||(e[4]=o("p",null,[a("All notable changes to "),o("strong",null,"FalconCMS"),a(" are documented here."),o("br"),a(" Format follows "),o("a",{href:"https://keepachangelog.com/en/1.0.0/",target:"_blank",rel:"noreferrer"},"Keep a Changelog"),a(" ‚Äî versions are sorted newest first.")],-1)),e[5]||(e[5]=o("hr",null,null,-1)),o("h2",h,[e[0]||(e[0]=a("v1.4.6 ",-1)),l(t,{type:"tip",text:"Latest"}),e[1]||(e[1]=a()),e[2]||(e[2]=o("a",{class:"header-anchor",href:"#v1-4-6","aria-label":'Permalink to "v1.4.6 <Badge type="tip" text="Latest" /> {#v1-4-6}"'},"‚Äã",-1))]),e[6]||(e[6]=d('<p><strong>Released: 2026-06-21</strong></p><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">‚Äã</a></h3><ul><li><strong><code>falcon:update</code> ‚Äî stale published view overrides</strong> ‚Äî Update now removes the entire published <code>resources/views/vendor/falcon-cms</code> directory, not just the <code>admin</code> subfolder. A leftover published copy of a namespaced package view (e.g. <code>frontend/builder/column.blade.php</code>) silently shadows the real vendor view, so layout fixes never appear on the site no matter how many caches are cleared. Clearing the whole override namespace guarantees the package&#39;s own views are always used</li></ul><h2 id="v1-4-5" tabindex="-1">v1.4.5 <a class="header-anchor" href="#v1-4-5" aria-label="Permalink to &quot;v1.4.5 {#v1-4-5}&quot;">‚Äã</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">‚Äã</a></h3><ul><li><strong>Dashboard Update ‚Äî stale frontend after update</strong> ‚Äî The dashboard &quot;Update&quot; now resets the php-fpm OPcache from the web request itself. Previously the <code>falcon:update</code> subprocess ran under CLI php, whose <code>opcache_reset()</code> only clears the CLI OPcache ‚Äî the php-fpm workers that serve frontend pages kept executing the old compiled Blade views, so builder/layout fixes did not appear on the live site until a manual container restart</li><li><strong>Dashboard footer</strong> ‚Äî Default admin footer credit changed to &quot;Theme developed by Falcon CMS&quot;</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">‚Äã</a></h3><ul><li><strong>Taxonomy screens</strong> ‚Äî Removed the non-functional &quot;Screen Options&quot; and &quot;Help&quot; buttons from the top-right of all taxonomy list pages (Categories, Tags, Product Categories, Product Tags, and custom ACPT taxonomy terms)</li></ul><h2 id="v1-4-4" tabindex="-1">v1.4.4 <a class="header-anchor" href="#v1-4-4" aria-label="Permalink to &quot;v1.4.4 {#v1-4-4}&quot;">‚Äã</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">‚Äã</a></h3><ul><li><strong>Dashboard Update ‚Äî php-fpm binary</strong> ‚Äî The dashboard &quot;Update&quot; button ran <code>falcon:update</code> with <code>PHP_BINARY</code>, which in a web (php-fpm) request points at the php-fpm executable and cannot run <code>artisan</code> (it printed FastCGI usage and aborted, so migrations/cache-clear/OPcache reset never ran). The updater now locates a real CLI php binary, checking absolute paths first since the php-fpm worker often runs with a stripped <code>PATH</code></li></ul><h2 id="v1-4-3" tabindex="-1">v1.4.3 <a class="header-anchor" href="#v1-4-3" aria-label="Permalink to &quot;v1.4.3 {#v1-4-3}&quot;">‚Äã</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="fixed-3" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-3" aria-label="Permalink to &quot;Fixed&quot;">‚Äã</a></h3><ul><li><strong>Page Builder ‚Äî Preview mode blank canvas</strong> ‚Äî Toggling the builder&#39;s eye-icon Preview no longer blanks the whole canvas. In preview the canvas kept <code>grid-area: auto</code>, which auto-placed it into the now-hidden sidebar&#39;s 0-width grid column; it is now pinned to its named <code>canvas</code> area so the design stays visible</li></ul><h2 id="v1-4-2" tabindex="-1">v1.4.2 <a class="header-anchor" href="#v1-4-2" aria-label="Permalink to &quot;v1.4.2 {#v1-4-2}&quot;">‚Äã</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="fixed-4" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-4" aria-label="Permalink to &quot;Fixed&quot;">‚Äã</a></h3><ul><li><strong>Page Builder ‚Äî Row content layout</strong> ‚Äî Elements inside a column with Content Layout set to &quot;Row&quot; now stay side-by-side and never wrap to the next line (<code>flex-wrap: nowrap</code>); previously <code>flex-wrap: wrap</code> caused elements to stack when they did not fit</li><li><strong><code>falcon:update</code> ‚Äî OPcache</strong> ‚Äî OPcache is now reset after cache clearing so freshly compiled Blade views are served immediately without requiring a server restart</li></ul><hr><h2 id="v1-4-1" tabindex="-1">v1.4.1 <a class="header-anchor" href="#v1-4-1" aria-label="Permalink to &quot;v1.4.1 {#v1-4-1}&quot;">‚Äã</a></h2><p><strong>Released: 2026-06-21</strong></p><h3 id="fixed-5" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-5" aria-label="Permalink to &quot;Fixed&quot;">‚Äã</a></h3><ul><li><strong>Multi-device login</strong> ‚Äî <code>-1</code> value for Max Devices now correctly means unlimited; previously <code>count() &gt;= -1</code> was always true, blocking all logins even when unlimited was intended</li><li><strong>Page Builder ‚Äî Nested Column row layout</strong> ‚Äî Elements inside a column with Content Layout set to &quot;Row&quot; now render side-by-side on the frontend; previously <code>width: 100%</code> on element wrappers caused items to stack vertically despite <code>flex-direction: row</code></li></ul><hr><h2 id="v1-4-0" tabindex="-1">v1.4.0 <a class="header-anchor" href="#v1-4-0" aria-label="Permalink to &quot;v1.4.0 {#v1-4-0}&quot;">‚Äã</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">‚Äã</a></h3><ul><li><strong>Demo mode ‚Äî Login page</strong> ‚Äî Demo credentials box displayed above login form when <code>APP_DEMO=true</code></li><li><strong>Demo mode ‚Äî User management</strong> ‚Äî All fields on user create and user edit pages disabled with warning banner when <code>APP_DEMO=true</code></li><li><strong>Demo mode ‚Äî Settings</strong> ‚Äî <code>register_url</code> and <code>login_url</code> inputs disabled with warning banner when <code>APP_DEMO=true</code></li><li><strong>Docs ‚Äî Demo page</strong> ‚Äî Live demo request page with lead capture form; credentials sent to visitor&#39;s email via EmailJS after form submission</li></ul><h3 id="fixed-6" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-6" aria-label="Permalink to &quot;Fixed&quot;">‚Äã</a></h3><ul><li><strong>Footer logo</strong> ‚Äî Default FalconCMS logo always shown in footer column 1; embedded as base64 to remove file dependency; <code>theme_footer_logo</code> / <code>theme_site_logo</code> cleared from DB on <code>falcon:update</code> so stale overrides are never applied</li><li><strong><code>falcon:update</code></strong> ‚Äî Published admin views deleted on update so vendor views are always served fresh (no stale published copies)</li></ul><hr><h2 id="v1-3-18" tabindex="-1">v1.3.18 <a class="header-anchor" href="#v1-3-18" aria-label="Permalink to &quot;v1.3.18 {#v1-3-18}&quot;">‚Äã</a></h2><p><strong>Released: 2026-06-20</strong></p><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">‚Äã</a></h3><ul><li><strong>Customizer ‚Äî Performance</strong> ‚Äî &quot;Clear All Cache&quot; button for one-click cache clearing from the admin</li></ul><h3 id="fixed-7" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-7" aria-label="Permalink to &quot;Fixed&quot;">‚Äã</a></h3><ul><li><strong>Product editor</strong> ‚Äî Added <code>x-cloak</code> to product data metabox to prevent Alpine.js FOUC on page load</li><li><strong><code>falcon:update</code></strong> ‚Äî Admin views automatically re-published during update to keep published copies in sync</li><li><strong>Sale end date</strong> ‚Äî <code>sale_ends_at</code> datetime input minimum set using client-side local time instead of server UTC</li><li><strong>Product archive</strong> ‚Äî <code>productCategories</code> relation used in <code>archive-product.blade.php</code>; eager loaded on CPT archive queries to prevent N+1</li><li><strong>Sale end date validation</strong> ‚Äî Removed <code>after:now</code> rule causing false rejections in some timezones</li><li><strong>PHP_BINARY</strong> ‚Äî Correctly resolved to CLI <code>php</code> in web (php-fpm) context</li><li><strong>Product categories</strong> ‚Äî Category label display corrected on product cards and single product pages</li><li><strong>Shop</strong> ‚Äî Tab active-state bug fixed; <code>hold_stock</code> order cancellation implemented</li><li><strong>Page Builder</strong> ‚Äî Fixed offset constants in <code>parseColumnsFromContent()</code></li><li><strong>Hooks &amp; helpers</strong> ‚Äî Remaining <code>lazy_</code> class and helper references renamed to <code>falcon_</code></li></ul><hr><h2 id="v1-0-0" tabindex="-1">v1.0.0 <a class="header-anchor" href="#v1-0-0" aria-label="Permalink to &quot;v1.0.0 {#v1-0-0}&quot;">‚Äã</a></h2><p><strong>Released: 2026-06-15</strong></p><p>Initial public release of <strong>FalconCMS</strong> ‚Äî a powerful Laravel CMS package with page builder, e-commerce, and a WordPress-like admin dashboard.</p><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to &quot;Core&quot;">‚Äã</a></h3><ul><li><strong>WordPress-like Admin Dashboard</strong> ‚Äî Sidebar navigation, top bar, role-based permissions, activity logs</li><li><strong>Page Builder (Falcon Builder)</strong> ‚Äî Drag-and-drop visual editor with rows, columns, and element blocks</li><li><strong>Post &amp; Page Management</strong> ‚Äî Custom post types, categories, tags, featured images, SEO fields</li><li><strong>Media Library</strong> ‚Äî Upload, manage, and select images/files across the admin</li><li><strong>User &amp; Role Management</strong> ‚Äî Granular permission system with custom roles</li><li><strong>Multi-language Support</strong> ‚Äî Built-in language management</li><li><strong>Theme System</strong> ‚Äî Installable themes with Customizer support (header, footer, colors, typography)</li><li><strong>Hook Architecture</strong> ‚Äî WordPress-style <code>add_lazy_action</code> / <code>add_lazy_filter</code> for extensibility</li><li><strong>Custom Options Pages</strong> ‚Äî Register custom settings pages via config</li></ul><h3 id="e-commerce-shop" tabindex="-1">E-Commerce (Shop) <a class="header-anchor" href="#e-commerce-shop" aria-label="Permalink to &quot;E-Commerce (Shop)&quot;">‚Äã</a></h3><ul><li><strong>Product Management</strong> ‚Äî Simple and variable products, SKU, stock, sale price with scheduled expiry (<code>sale_ends_at</code>)</li><li><strong>Digital / Downloadable Products</strong> ‚Äî Attach files from the media library; secure token-based download links with expiry and download count limits</li><li><strong>Orders</strong> ‚Äî Full order lifecycle (pending ‚Üí processing ‚Üí shipped ‚Üí completed), order notes, status history</li><li><strong>Cart &amp; Checkout</strong> ‚Äî AJAX cart, coupon codes, shipping zones, tax rules</li><li><strong>Payments</strong> ‚Äî Cash on Delivery, Stripe, SSLCommerz integrations</li><li><strong>Customer Account</strong> ‚Äî Order history, downloads tab, address management</li><li><strong>Sales Reports</strong> ‚Äî Revenue by period (daily/weekly/monthly), top products, customer LTV, CSV export</li><li><strong>Shop Settings</strong> ‚Äî Currency, inventory, email notifications, shipping, tax, coupon management</li></ul><h3 id="admin-ui" tabindex="-1">Admin UI <a class="header-anchor" href="#admin-ui" aria-label="Permalink to &quot;Admin UI&quot;">‚Äã</a></h3><ul><li><strong>URL-aware Settings Tabs</strong> ‚Äî Tab switches update the browser URL via <code>history.replaceState</code></li><li><strong>Sidebar Collapse</strong> ‚Äî &quot;Collapse Menu&quot; button; icon-only mode persisted in <code>localStorage</code> with no flash on navigation</li><li><strong>FalconCMS Branding</strong> ‚Äî FCM logo in admin top bar</li></ul><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">‚Äã</a></h3><ul><li><strong>HTTP Security Headers</strong> ‚Äî <code>X-Content-Type-Options</code>, <code>X-Frame-Options</code>, <code>Referrer-Policy</code>, <code>Permissions-Policy</code>, CSP, HSTS</li><li><strong>Rate Limiting</strong> ‚Äî Login, forgot-password, comments, cart operations, file downloads</li><li><strong>CSRF Protection</strong> ‚Äî All state-changing routes protected</li><li><strong>Input Validation</strong> ‚Äî Cart quantities, file uploads, comment length, user enumeration prevention</li><li><strong>Secure Downloads</strong> ‚Äî Token-based file delivery; tokens expire and have per-user download limits</li></ul><h3 id="developer-tools" tabindex="-1">Developer Tools <a class="header-anchor" href="#developer-tools" aria-label="Permalink to &quot;Developer Tools&quot;">‚Äã</a></h3><ul><li><strong>Artisan Commands</strong> ‚Äî <code>lazy:expire-sales</code> (scheduled sale price cleanup)</li><li><strong>REST API</strong> ‚Äî Configurable API key authentication</li><li><strong>Backup &amp; Snapshots</strong> ‚Äî Database and file backup tools</li><li><strong>WordPress Import</strong> ‚Äî Import posts from a WordPress XML export</li><li><strong>Analytics Dashboard</strong> ‚Äî Basic traffic and content stats</li><li><strong>Maintenance Mode</strong> ‚Äî Toggle from Customizer with custom message and countdown timer</li></ul>',54))])}const x=r(c,[["render",u]]);export{w as __pageData,x as default};
